function fnv1a(seedString){let hash=2166136261;for(let i=0;i<seedString.length;i++){hash=Math.imul(hash^seedString.charCodeAt(i),16777619)}return hash>>>0}function mulberry32(seed){return()=>{let value=seed+=1831565813;value=Math.imul(value^value>>>15,value|1);value^=value+Math.imul(value^value>>>7,value|61);return((value^value>>>14)>>>0)/4294967296}}function hslToHex(hue,saturation,lightness){const factor=saturation*Math.min(lightness,1-lightness);const channel=offset=>{const position=(offset+hue*12)%12;const color=lightness-factor*Math.max(Math.min(position-3,9-position,1),-1);return Math.round(color*255).toString(16).padStart(2,"0")};return"#"+channel(0)+channel(8)+channel(4)}function draw(source,options={}){const padding=options.padding||0;const background=options.background;const viewWidth=source.width+padding*2;const viewHeight=source.height+padding*2;return{svg(){let rects="";source.each((x,y,color)=>{rects+=`<rect x="${padding+x}" y="${padding+y}" width="1" height="1" fill="${color}" />\n`});let backgroundRect="";if(background){backgroundRect=`<rect width="${viewWidth}" height="${viewHeight}" fill="${background}" />\n`}return`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${viewWidth} ${viewHeight}" width="100%" height="100%" shape-rendering="crispEdges">\n${backgroundRect}${rects}</svg>`},canvas(canvas,scale){const context=canvas.getContext("2d");canvas.width=viewWidth*scale;canvas.height=viewHeight*scale;if(background){context.fillStyle=background;context.fillRect(0,0,canvas.width,canvas.height)}source.each((x,y,color)=>{context.fillStyle=color;context.fillRect((padding+x)*scale,(padding+y)*scale,scale,scale)})},url(){const svg=this.svg();const bytes=(new TextEncoder).encode(svg);const binString=Array.from(bytes,byte=>String.fromCharCode(byte)).join("");return"data:image/svg+xml;base64,"+btoa(binString)}}}function base(config){const{seed:seed,width:width,height:height,colors:colors,density:density,symmetry:symmetry}=config;const random=mulberry32(fnv1a(seed));const palette=Array.from({length:colors},()=>hslToHex(random(),random()*.85+.15,random()*.76+.12));const map=Array.from({length:height},()=>Array(width).fill(null));if(symmetry){for(const coordinates of symmetry){if(random()<density){const color=palette[Math.floor(random()*palette.length)];for(const coord of coordinates){map[coord.y][coord.x]=color}}}}else{for(let y=0;y<height;y++){for(let x=0;x<width;x++){if(random()<density){map[y][x]=palette[Math.floor(random()*palette.length)]}}}}const each=callback=>{for(let y=0;y<height;y++){for(let x=0;x<width;x++){if(map[y][x]){callback(x,y,map[y][x])}}}};const source={seed:seed,width:width,height:height,each:each};return{...source,...draw(source)}}const symmetries={horizontal(width,height){const regions=[];for(let y=0;y<height;y++){for(let x=0;x<Math.ceil(width/2);x++){regions.push([{x:x,y:y},{x:width-1-x,y:y}])}}return regions},vertical(width,height){const regions=[];for(let y=0;y<Math.ceil(height/2);y++){for(let x=0;x<width;x++){regions.push([{x:x,y:y},{x:x,y:height-1-y}])}}return regions}};function sand(config){const{symmetry:symmetry,padding:padding=0,background:background}=config;const innerWidth=Math.max(1,config.width-padding*2);const innerHeight=Math.max(1,config.height-padding*2);const source=base({...config,width:innerWidth,height:innerHeight,symmetry:symmetries[symmetry]?symmetries[symmetry](innerWidth,innerHeight):null});return{...source,width:config.width,height:config.height,...draw(source,{padding:padding,background:background})}}sand.url=seed=>sand({seed:seed,width:10,height:10,colors:2,density:.6,padding:1}).url();export{symmetries,base as sand};export default sand;